import React, { useState } from 'react';

const App = () => {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [saved, setSaved] = useState(false);

  const handleSave = () => {
    setSaved(true);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="p-4 bg-white shadow-md w-[400px]">
        <input type="text" className="p-2 w-full mb-4" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Title"/>
        <textarea className="p-2 w-full" value={content} onChange={(e) => setContent(e.target.value)} placeholder="Content"/>
        <button className="bg-[#C06C88] p-2 text-white" onClick={handleSave}>Save</button>
      </div>
    </div>
  );
};

export default App;
